// Test: Constructor and property initialization
public class Customer
{
    public string Name { get; set; }
    public int Age { get; set; }
    public bool IsActive { get; set; }

    public Customer(string name, int age)
    {
        if (string.IsNullOrEmpty(name))
        {
            throw new ArgumentException("Name cannot be empty");
        }

        if (age < 0)
        {
            throw new ArgumentException("Age cannot be negative");
        }

        Name = name;
        Age = age;
        IsActive = true;
    }

    public void DeactivateIfOld()
    {
        if (Age > 65)
        {
            IsActive = false;
        }
    }
}

// Test: Email validation with complex logic
public class Validator
{
    public bool IsValidEmail(string email)
    {
        if (string.IsNullOrEmpty(email))
        {
            return false;
        }

        if (!email.Contains("@"))
        {
            return false;
        }

        string[] parts = email.Split('@');
        if (parts.Length != 2)
        {
            return false;
        }

        return !string.IsNullOrEmpty(parts[0]) && !string.IsNullOrEmpty(parts[1]);
    }
}

// Test: Generic methods and type constraints
public class GenericProcessor<T> where T : IComparable<T>
{
    public T FindMax(List<T> items)
    {
        if (items == null || items.Count == 0)
        {
            throw new ArgumentException("List cannot be null or empty");
        }

        T max = items[0];

        for (int i = 1; i < items.Count; i++)
        {
            if (items[i].CompareTo(max) > 0)
            {
                max = items[i];
            }
        }

        return max;
    }

    public List<T> FilterAndSort(List<T> items, Func<T, bool> predicate)
    {
        var filtered = new List<T>();

        foreach (var item in items)
        {
            if (predicate(item))
            {
                filtered.Add(item);
            }
        }

        filtered.Sort();
        return filtered;
    }
}

// Test: LINQ and method chaining
using System.Linq;

public class DataProcessor
{
    public List<int> ProcessNumbers(List<int> numbers)
    {
        return numbers
            .Where(n => n > 0)
            .Where(n => n < 100)
            .Select(n => n * 2)
            .OrderBy(n => n)
            .ToList();
    }

    public string ProcessStrings(List<string> strings)
    {
        var result = strings
            .Where(s => !string.IsNullOrEmpty(s))
            .Select(s => s.Trim().ToUpper())
            .FirstOrDefault();

        return result ?? "No valid string found";
    }
}

